# Burn rate formula for 99.9% SLO (error budget fraction = 0.001)
# Substitute your service name and status code labels as appropriate.

# 5-minute window burn rate
(
  sum(rate(http_requests_total{
    service="claude-integration",
    status_code=~"5.."
  }[5m]))
  /
  sum(rate(http_requests_total{
    service="claude-integration",
    status_code!~"4.."
  }[5m]))
)
/ 0.001   # = 1 - 0.999 (the error budget fraction for a 99.9% SLO)

# 1-hour window burn rate
(
  sum(rate(http_requests_total{
    service="claude-integration",
    status_code=~"5.."
  }[1h]))
  /
  sum(rate(http_requests_total{
    service="claude-integration",
    status_code!~"4.."
  }[1h]))
)
/ 0.001

# Latency SLO burn rate alert — 95% of requests under 2s (error budget = 0.05)
- alert: ClaudeIntegrationLatencyBurn
  expr: |
    (
      # fraction of requests EXCEEDING 2s threshold in 5-min window
      (
        1 - sum(rate(http_request_duration_seconds_bucket{
            service="claude-integration",
            le="2.0"
        }[5m]))
        /
        sum(rate(http_request_duration_seconds_count{
            service="claude-integration"
        }[5m]))
      )
    ) / 0.05  # error budget fraction for 95% latency SLO
    > 14  # 14x burn rate threshold
    and
    (
      (
        1 - sum(rate(http_request_duration_seconds_bucket{
            service="claude-integration",
            le="2.0"
        }[1h]))
        /
        sum(rate(http_request_duration_seconds_count{
            service="claude-integration"
        }[1h]))
      )
    ) / 0.05
    > 14
  for: 2m
  labels:
    severity: critical
    slo: claude-integration-latency
  annotations:
    summary: "Critical latency SLO burn: {{ $value }}x rate (14x budget consumption)"
